<?php
 namespace FilesManager; class DirectoryTree { private string $basePath; public function __construct(string $basePath) { $this->basePath = realpath($basePath); if ($this->basePath === false || !is_dir($this->basePath)) { throw new \Exception('Base path inválido'); } } public function getTree(string $path = '/', bool $showHiddenFiles = false): array { $fullPath = Validator::validatePath($path, $this->basePath); if ($fullPath === false || !is_dir($fullPath)) { throw new \Exception('Diretório inválido'); } $isWritable = is_writable($fullPath); return [ 'items' => $this->buildTree($fullPath, $showHiddenFiles), 'permissions' => [ 'readable' => is_readable($fullPath), 'writable' => $isWritable, 'executable' => is_executable($fullPath), ], ]; } private function buildTree(string $path, bool $showHiddenFiles = false): array { $tree = []; $entries = scandir($path); foreach ($entries as $entry) { if ($entry === '.' || $entry === '..') { continue; } if (str_ends_with($entry, '.meta.json')) { continue; } if (!$showHiddenFiles && strpos($entry, '.') === 0) { continue; } $itemPath = $path . '/' . $entry; if (!is_dir($itemPath)) { continue; } $relativePath = str_replace($this->basePath, '', $itemPath); $tree[] = [ 'name' => $entry, 'path' => $relativePath, 'hasChildren' => $this->hasSubdirectories($itemPath, $showHiddenFiles), 'expanded' => false, 'children' => null, ]; } usort($tree, function ($a, $b) { return strcasecmp($a['name'], $b['name']); }); return $tree; } private function hasSubdirectories(string $path, bool $showHiddenFiles = false): bool { if (!is_dir($path)) { return false; } $entries = scandir($path); foreach ($entries as $entry) { if ($entry === '.' || $entry === '..') { continue; } if (str_ends_with($entry, '.meta.json')) { continue; } if (!$showHiddenFiles && strpos($entry, '.') === 0) { continue; } if (is_dir($path . '/' . $entry)) { return true; } } return false; } public function getChildren(string $path, bool $showHiddenFiles = false): array { return $this->getTree($path, $showHiddenFiles); } public function getBreadcrumb(string $path): array { $fullPath = Validator::validatePath($path, $this->basePath); if ($fullPath === false) { return [ [ 'name' => 'Root', 'path' => '/', ] ]; } $relativePath = str_replace($this->basePath, '', $fullPath); $parts = array_filter(explode('/', $relativePath)); $breadcrumb = [ [ 'name' => 'Root', 'path' => '/', ] ]; $currentPath = ''; foreach ($parts as $part) { $currentPath .= '/' . $part; $breadcrumb[] = [ 'name' => $part, 'path' => $currentPath, ]; } return $breadcrumb; } } 